import java.util.*;
public class Summer {
    public static int sum(List<Integer> nums) {
        int total = 0;
        for (int n : nums) {
            total += n;
        }
        return total;
    }

    public static void main(String[] args) {
        List<Integer> data = new ArrayList<>(Arrays.asList(1, 2, null, 4));
        System.out.println(sum(data));
    }
}
